import heapq

class Solution:
    def minCost(self, n, prices, roads):
        adj_cost = [[] for _ in range(n)]
        adj_tax = [[] for _ in range(n)]
        for u, v, cost, tax in roads:
            adj_cost[u].append((v, cost))
            adj_cost[v].append((u, cost))
            taxed = cost * tax
            adj_tax[u].append((v, taxed))
            adj_tax[v].append((u, taxed))

        def dijkstra(adj, src):
            dist = [float('inf')] * n
            dist[src] = 0
            pq = [(0, src)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, w in adj[u]:
                    nd = d + w
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist

        ans = []
        for i in range(n):
            dc = dijkstra(adj_cost, i)
            dt = dijkstra(adj_tax, i)
            best = prices[i]
            for j in range(n):
                if dc[j] == float('inf') or dt[j] == float('inf'):
                    continue
                total = dc[j] + dt[j] + prices[j]
                if total < best:
                    best = total
            ans.append(best)
        return ans

