function dijkstra(adj, src, n) {
    const dist = new Array(n).fill(Infinity);
    dist[src] = 0;
    const visited = new Array(n).fill(false);
    const pq = [[0, src]];
    while (pq.length) {
        pq.sort((a, b) => a[0] - b[0]);
        const [d, u] = pq.shift();
        if (visited[u]) continue;
        visited[u] = true;
        for (const [v, w] of adj[u]) {
            const nd = d + w;
            if (nd < dist[v]) {
                dist[v] = nd;
                pq.push([nd, v]);
            }
        }
    }
    return dist;
}

var minCost = function(n, prices, roads) {
    const adjCost = Array.from({ length: n }, () => []);
    const adjTax = Array.from({ length: n }, () => []);
    for (const [u, v, cost, tax] of roads) {
        adjCost[u].push([v, cost]);
        adjCost[v].push([u, cost]);
        const taxed = cost * tax;
        adjTax[u].push([v, taxed]);
        adjTax[v].push([u, taxed]);
    }
    const ans = [];
    for (let i = 0; i < n; i++) {
        const dc = dijkstra(adjCost, i, n);
        const dt = dijkstra(adjTax, i, n);
        let best = prices[i];
        for (let j = 0; j < n; j++) {
            if (dc[j] === Infinity || dt[j] === Infinity) continue;
            const total = dc[j] + dt[j] + prices[j];
